#include <stdio.h>
#include <stdint.h>

int64_t mod = 10007;

int64_t powmod(int64_t base, int64_t exponent) {
    int64_t result = 1;
    while (exponent > 0) {
        if (exponent & 1) {
            result = (result * base) % mod;
        }
        base = (base * base) % mod;
        exponent >>= 1;
    }
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int64_t R, C, N;
        scanf("%lld %lld %lld", &R, &C, &N);
        if (N > R || N > C) {
            printf("0\n");
        } else {
            int64_t result = 0;
            for (int64_t i = 0; i <= N; i++) {
                int64_t term = powmod(i, R) * powmod(N - i, C);
                term %= mod;
                result += term;
                result %= mod;
            }
            printf("%lld\n", result);
        }
    }
    return 0;
}

